// AUTO-GENERATED by Lovable Visual Editor. Do not edit by hand.
// Tags every JSX opening element with data-vse="<file>:<line>:<col>" so the
// live editor can map iframe clicks back to source positions.
module.exports = function visualEditorBabelPlugin({ types: t }) {
  return {
    name: "visual-editor-source-tag",
    visitor: {
      JSXOpeningElement(path, state) {
        if (!process.env.VITE_VISUAL_EDITOR) return;
        const loc = path.node.loc;
        const file = state.file.opts.filename;
        if (!loc || !file) return;
        if (file.includes("node_modules")) return;
        // dedupe
        if (path.node.attributes.some((a) => a && a.name && a.name.name === "data-vse")) return;
        const cwd = state.cwd || process.cwd();
        const rel = file.startsWith(cwd) ? file.slice(cwd.length + 1) : file;
        path.node.attributes.push(
          t.jsxAttribute(
            t.jsxIdentifier("data-vse"),
            t.stringLiteral(rel + ":" + loc.start.line + ":" + loc.start.column),
          ),
        );
      },
    },
  };
};
